var e=[{id:`L2_1`,type:`dialog`,speaker:`SURYA_VARUNA_NULL_NULL`,text:{KOREA:`빛 하나 없는 어둠 속에 갇힐지라도, 포기하지말고 일어서라.`,JPN:`光一つない闇の中に閉じ込められても、諦めずに立ち上がれ。 `,ENG:`Even if you are trapped in darkness without light, stand back up and never give up.`,TWN:`即使被困在沒有一絲光明的黑暗中，也不要放棄，起來。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SURYA_VARUNA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SURYA_VARUNA_NULL_NULL`,text:{KOREA:`모든 것을 잃을지라도, 어떻게든 나아간다면… 인도하는 태양은 늘 그렇듯, 당신을 향해 손을 내밀어줄 테니까.`,JPN:`すべてを失っても、前へ進み続ければ……導く太陽はいつでも、あなたに手を差し伸べてくれるから。`,ENG:`Even if you lose everything, if you keep marching onward... I will reach out my hand as the guiding sun like I always have.`,TWN:`即使失去一切，只要繼續前行……引導的太陽依舊會向你伸出援手。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SURYA_VARUNA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};